(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"discount-price",fields:[{"key":"price","label":"원래 가격 (원)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"rate","label":"할인율 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var p=Number(x.price),r=Number(x.rate);if(!Number.isFinite(p)||!Number.isFinite(r)||p<0)return{error:"가격과 할인율을 올바르게 입력해 주세요."};return{value:p*(1-r/100)};},format:function(r,api){return api.resultCard("할인 후 가격",api.formatWon(r.value),"");}},{id:"price-change-rate",fields:[{"key":"old","label":"이전 가격","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"newv","label":"새 가격","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.old),b=Number(x.newv);if(!Number.isFinite(a)||!Number.isFinite(b)||a===0)return{error:"이전 가격은 0이 아닌 값이어야 합니다."};return{value:(b-a)/a*100};},format:function(r,api){return api.resultCard("가격 변동률",api.formatNumber(r.value,6)+"%","");}},{id:"tip",fields:[{"key":"amount","label":"결제 금액","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"rate","label":"팁 비율 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.amount),r=Number(x.rate);if(!Number.isFinite(a)||!Number.isFinite(r)||a<0)return{error:"금액과 비율을 올바르게 입력해 주세요."};return{value:a*r/100};},format:function(r,api){return api.resultCard("팁 금액",api.formatWon(r.value),"");}},{id:"custom-fee-total",fields:[{"key":"amount","label":"기준 금액","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"rate","label":"수수료율 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.amount),r=Number(x.rate);if(!Number.isFinite(a)||!Number.isFinite(r))return{error:"금액과 수수료율을 입력해 주세요."};return{value:a*(1+r/100)};},format:function(r,api){return api.resultCard("수수료 포함 총액",api.formatWon(r.value),"");}},{id:"savings-progress",fields:[{"key":"current","label":"현재 값","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"target","label":"목표 값","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var c=Number(x.current),t=Number(x.target);if(!Number.isFinite(c)||!Number.isFinite(t)||t===0)return{error:"목표 값은 0이 아닌 값이어야 합니다."};return{value:c/t*100};},format:function(r,api){return api.resultCard("목표 달성률",api.formatNumber(r.value,6)+"%","");}},{id:"target-difference",fields:[{"key":"current","label":"현재 값","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"target","label":"목표 값","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var c=Number(x.current),t=Number(x.target);if(!Number.isFinite(c)||!Number.isFinite(t))return{error:"현재 값과 목표 값을 입력해 주세요."};return{value:t-c};},format:function(r,api){return api.resultCard("목표까지 차이",api.formatNumber(r.value,10)+"","");}},{id:"hourly-cost",fields:[{"key":"cost","label":"총 비용","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"hours","label":"총 사용 시간","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var c=Number(x.cost),h=Number(x.hours);if(!Number.isFinite(c)||!Number.isFinite(h)||h<=0)return{error:"사용 시간은 0보다 커야 합니다."};return{value:c/h};},format:function(r,api){return api.resultCard("시간당 비용",api.formatWon(r.value),"");}},{id:"daily-budget",fields:[{"key":"budget","label":"전체 예산","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"days","label":"일수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var b=Number(x.budget),d=Number(x.days);if(!Number.isFinite(b)||!Number.isInteger(d)||d<=0)return{error:"예산과 1일 이상의 일수를 입력해 주세요."};return{value:b/d};},format:function(r,api){return api.resultCard("하루 예산",api.formatWon(r.value),"");}},{id:"annual-subscription",fields:[{"key":"monthly","label":"월 구독료","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var m=Number(x.monthly);if(!Number.isFinite(m)||m<0)return{error:"월 구독료를 올바르게 입력해 주세요."};return{value:m*12};},format:function(r,api){return api.resultCard("연간 구독 비용",api.formatWon(r.value),"");}},{id:"cost-per-use",fields:[{"key":"cost","label":"총 구매 비용","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"uses","label":"사용 횟수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var c=Number(x.cost),u=Number(x.uses);if(!Number.isFinite(c)||!Number.isInteger(u)||u<=0)return{error:"사용 횟수는 1 이상이어야 합니다."};return{value:c/u};},format:function(r,api){return api.resultCard("1회당 비용",api.formatWon(r.value),"");}},{id:"consumption-cost",fields:[{"key":"quantity","label":"사용량","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"unitPrice","label":"단위당 가격","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var q=Number(x.quantity),p=Number(x.unitPrice);if(!Number.isFinite(q)||!Number.isFinite(p)||q<0||p<0)return{error:"사용량과 단가를 올바르게 입력해 주세요."};return{value:q*p};},format:function(r,api){return api.resultCard("총 비용",api.formatWon(r.value),"");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);